import { use, useEffect, useState } from "react";

const allProducts = 'https://dummyjson.com/products?limit=0'
const paginatedProducts = 'https://dummyjson.com/products'
const paginatedQueryParam = (limit,skipResult) => `?limit=${limit}&skip=${skipResult}`
export const pageLimit = 10
async function getData(skipResult = 0, limit = 10) {
    const resp = await fetch(paginatedProducts + paginatedQueryParam(10,skipResult))
    const data = await resp.json()
    return data
}
function useData(skipResult = 0) {
    console.log('>>>>', skipResult)

    const [data, setData] = useState({
        loading: false,
        error: null,
        tableData: null,
        total: null,
        skip: null
    })

   async function fetchData(skipResult) {
    setData((prev) => {
        return {
          ...prev,
          loading: true
        }
    })
    try{
        const data = await getData(skipResult)
        setData((prev) => {
        return {
          ...prev,
          tableData: data?.products,
          total: data?.total,
          skip: data?.skip
        }
        })
    } catch (err) {
setData((prev) => {
        return {
          ...prev,
          error: 'Error'
        }
        })
    } finally {
        setData((prev) => {
        return {
          ...prev,
          loading: false
        }
        })
    }
   }
    useEffect(() => {
      fetchData()
    },[skipResult])
    return data
}

export default useData
